-- ----------------------------
-- Table structure for ecms_contract_type
-- ----------------------------
DROP TABLE IF EXISTS `ecms_contract_type`;
CREATE TABLE `ecms_contract_type` (
  `id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '合同类型ID',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '合同类型名称',
  `code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '合同类型编号',
