-- ----------------------------
-- Table structure for ecms_contract_type_category
-- ----------------------------
DROP TABLE IF EXISTS `ecms_contract_type_category`;
CREATE TABLE `ecms_contract_type_category` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '合同类型分类id',
  `parent_id` int DEFAULT NULL COMMENT '合同类型分类父id',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '合同类型分类名称',
  `code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '合同类型分类编码',
  `deleted` bit(1) NOT NULL DEFAULT b'0' COMMENT '删除标记',
  `creator` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `updater` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '修改人',
  `update_time` datetime DEFAULT NULL COMMENT '修改时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- ----------------------------
-- Table structure for ecms_demo
-- ----------------------------
DROP TABLE IF EXISTS `ecms_demo`;
CREATE TABLE `ecms_demo` (
  `id` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL,
  `name` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '姓名',
  `deleted` int NOT NULL DEFAULT '0' COMMENT '删除标志;删除标志 0 正常 1删除',
  `creator` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `updater` varchar(256) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '修改人',
