-- ----------------------------
-- Table structure for ecms_ledger
-- ----------------------------
DROP TABLE IF EXISTS `ecms_ledger`;
CREATE TABLE `ecms_ledger` (
  `id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '主键id',
  `code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '合同编号',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '合同名称',
  `contract_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '合同类型（all=全部、sales=销售合同、purchase=采购合同、rental =租赁合同、transportation =运输合同、warehousing =仓储合同 等）',
  `contract_status` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '合同状态（all=全部，signing=签署中，signed=签署完成，unsigned=签署未完成，overdue_unsigned=逾期未签署、voiding=作废中、voided=已作废、terminating=终止中、terminated=已终止、filed=已归档、fufilling=履约中、overdue_fufilling=履约超期、pause_fulfil=履约暂停、finished=合同完成、overdue_finished=合同超期完成）',
  `contract_finance` decimal(10,2) DEFAULT NULL COMMENT '合同金额',
  `my_contract_party` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '我方签约主体',
  `counterparty` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '相对方签约主体',
  `sign_time` datetime DEFAULT NULL COMMENT '合同签订时间',
  `filing_time` datetime DEFAULT NULL COMMENT '合同归档时间',
  `sign_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '合同签署方式（all=全部，scan=扫码签、ukey=Ukey签署）',
  `sealing_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '合同用章类型(all=全部，contract =合同章、official =公章、corporate =法人章\r\n\r\n)',
  `creator` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `create_time` datetime NOT NULL,
  `updater` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `update_time` datetime DEFAULT NULL,
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0=没删除，1=已删除',
  `upload_file_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '上传文件访问路径',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin COMMENT='台账表';

-- ----------------------------
-- Table structure for ecms_model
-- ----------------------------
DROP TABLE IF EXISTS `ecms_model`;
CREATE TABLE `ecms_model` (
  `id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '模板id',
  `code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '模板编码',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '模板名称',
  `category_id` int DEFAULT NULL COMMENT '模板分类ID',
  `contract_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '合同类型',
  `time_effect_model` bit(1) DEFAULT NULL COMMENT '时效模式 ( 0=部分时间有效，1=长期有效 )',
  `effect_start_time` datetime DEFAULT NULL COMMENT '模板生效时间',
  `effect_end_time` datetime DEFAULT NULL COMMENT '模板失效时间',
  `content` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '模板描述(小于500字)',
  `model_file_path` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '模板文件，存放的是文件路径',
  `deleted` bit(1) DEFAULT b'0' COMMENT '删除标志 0 正常 1删除',
  `creator` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `updater` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '修改人',
  `update_time` datetime DEFAULT NULL COMMENT '修改时间',
  `status` bit(1) DEFAULT NULL COMMENT '状态（1=开启，0=停用）',
  `approve_status` tinyint(1) DEFAULT NULL COMMENT '审批状态（0=未审核，1=通过，2=不通过,，3=已审批）',
  `approve_time` datetime DEFAULT NULL COMMENT '审批时间',
  `file_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '合同模板文件名称',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin COMMENT='模版表';

