  `category_id` int DEFAULT NULL COMMENT '相对方分类id',
  `entity_type` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '主体类型,  个人：1 ，企业：2，单位：3',
